pub struct Cache<'a, K, V> {
    items: HashMap<K, V>,
    name: &'a str,
}

pub fn new(name: &'a str) -> Self {
        Self {
            items: HashMap::new(),
            name,
        }
    }

pub fn get(&self, key: &K) -> Option<&V> {
        self.items.get(key)
    }

pub fn insert(&mut self, key: K, value: V) -> Option<V> {
        self.items.insert(key, value)
    }

